fun solve(s: String, k: Long): String {
    val result = mutableListOf<Char>()

    for (c in s) {
        when (c) {
            'a'..'z' -> result.add(c)
            '*' -> {
                if (result.isNotEmpty()) {
                    result.removeAt(result.size - 1)
                }
            }
            '#' -> {
                val temp = mutableListOf<Char>()
                for (ch in result) {
                    temp.add(ch)
                }
                for (ch in temp) {
                    result.add(ch)
                }
            }
            '%' -> {
                result.reverse()
            }
        }
    }

    if (k < 0 || k >= result.size.toLong()) {
        return "."
    }

    return result[k.toInt()].toString()
}
